  };
}

private async handleTwoFactorValidation(
    user: IUser,
    { method, code, backupCode }: IAuthTwoFactorVerify
): Promise<IAuthTwoFactorVerifyResult> {
    const retryAfterMs =
        await this.authTwoFactorUtil.getLockTwoFactorAttempt(user);
    if (retryAfterMs > 0) {
        throw new RequestTooManyException({
            statusCode:
                EnumAuthStatusCodeError.twoFactorAttemptTemporaryLock,
            message: 'auth.error.twoFactorAttemptTemporaryLock',
            messageProperties: {
                retryAfterSeconds: retryAfterMs / 1000,
            },
        });
    }

    const verified = await this.authTwoFactorUtil.verifyTwoFactor(
        user.twoFactor,
        {
            method,
            code,
            backupCode,
        }
    );
    if (!verified.isValid) {
        await this.userRepository.increaseTwoFactorAttempt(user.id);

        if (this.authTwoFactorUtil.checkAttempt(user)) {
            await this.authTwoFactorUtil.lockTwoFactorAttempt(user);
        }

        throw new UnauthorizedException({
            statusCode: EnumAuthStatusCodeError.twoFactorInvalid,
            message: 'auth.error.twoFactorInvalid',
        });
    }

    await this.userRepository.resetTwoFactorAttempt(user.id);

    return verified;
}

createPassword(
    userId: string,
    password: string,
    options?: IAuthPasswordOptions
): IAuthPassword {
    const today = this.helperService.dateCreate();
    const salt: string = this.helperService.bcryptGenerateSalt(
        this.passwordSaltLength
    );
    const passwordExpired: Date = this.helperService.dateForward(
        today,
        this.helperService.dateCreateDuration({
            seconds: options?.temporary
                ? this.passwordExpiredTemporaryInSeconds
                : this.passwordExpiredInSeconds,
        })
    );
    const passwordHash = this.helperService.bcryptHash(password, salt);
    const passwordPeriodExpired: Date = this.helperService.dateForward(
        today,
        this.helperService.dateCreateDuration({
            seconds: this.passwordPeriodInSeconds,
        })
    );
    const passwordEncrypted: string = this.encryptPassword(
        userId,
        password
    );

    return {
        passwordHash,
        passwordExpired,
        passwordCreated: today,
        passwordPeriodExpired,
        passwordEncrypted,
    };
}

private async createTokens(user: User): Promise<UserTokensDto> {
  const tokenConfig =
    this.configService.getOrThrow<TokenConfig>(TokenConfigName);

  const accessTokenKey = randomBytes(64).toString('hex');
  const refreshTokenKey = randomBytes(64).toString('hex');

  await this.createKeystore(user, accessTokenKey, refreshTokenKey);

  const accessTokenPayload = new TokenPayload(
    tokenConfig.issuer,
    tokenConfig.audience,
    user._id.toString(),
    accessTokenKey,
    tokenConfig.accessTokenValidity,
  );

  const refreshTokenPayload = new TokenPayload(
    tokenConfig.issuer,
    tokenConfig.audience,
    user._id.toString(),
    refreshTokenKey,
    tokenConfig.refreshTokenValidity,
  );

  const accessToken = await this.signToken(accessTokenPayload);
  if (!accessToken) throw new InternalServerErrorException();

  const refreshToken = await this.signToken(refreshTokenPayload);
  if (!refreshToken) throw new InternalServerErrorException();

  return new UserTokensDto({
    accessToken: accessToken,
    refreshToken: refreshToken,
  });
}

async createPaymentIntent(createPaymentIntentDto: CreatePaymentIntentDto) {
  try {
    const { amount, currency, description } = createPaymentIntentDto;

    // Create the payment intent on Stripe
    const paymentIntent = await this.stripe.paymentIntents.create({
      amount,
      currency,
      description,
      // automatic_payment_methods tells Stripe to enable compatible payment methods
      automatic_payment_methods: {
        enabled: true,
      },
    });

    this.logger.log(
      `Payment Intent created: ${paymentIntent.id} for ${amount} ${currency}`,
    );

    // Return the client secret - frontend needs this to confirm the payment
    return {
      clientSecret: paymentIntent.client_secret,
      paymentIntentId: paymentIntent.id,
    };
  } catch (error) {
    this.logger.error('Failed to create payment intent', error.stack);
    throw new BadRequestException(
      'Could not create payment intent. Please check your Stripe configuration.',
    );
  }
}

async setupIntentToPaymentIntent(setupIntentId: string): Promise<Stripe.PaymentIntent> {
  const setupIntent = await this.findSetupIntentById(setupIntentId)

  if (setupIntent instanceof Error) throw new BadRequestException(setupIntent.message)
  const paymentMethod = setupIntent.payment_method as Stripe.PaymentMethod
  const email = paymentMethod.billing_details.email as string
  const name = paymentMethod.billing_details.name as string
  const metadata = setupIntent.metadata as Stripe.Metadata

  const customer = await this.createCustomer(email, name, paymentMethod)

  const activePaymentMethod = await this.findOrAttachPaymentMethod(paymentMethod, customer)
  const idempotencyKey = crypto.randomUUID()

  const paymentIntent = await this.api.createPaymentIntent(
    {
      amount: Math.round(Number(metadata.amount)),
      currency: metadata.currency,
      customer: customer.id,
      payment_method: activePaymentMethod.id,
      automatic_payment_methods: { enabled: true, allow_redirects: 'never' },
      confirm: true,
      metadata: {
        ...setupIntent.metadata,
      },
    },
    { idempotencyKey: `${idempotencyKey}--pi` },
  )
  return paymentIntent
}

async remove(
    userId: string,
    deviceOwnershipId: string,
    requestLog: IRequestLog
): Promise<IResponseReturn<void>> {
    const existDeviceOwnership =
        await this.deviceOwnershipRepository.existActive(
            userId,
            deviceOwnershipId
        );
    if (!existDeviceOwnership) {
        throw new NotFoundException({
            statusCode: EnumDeviceStatusCodeError.notFound,
            message: 'device.error.notFound',
        });
    }

    try {
        const sessions =
            await this.sessionRepository.findActiveByDeviceOwnership(
                userId,
                existDeviceOwnership.id
            );

        await Promise.all([
            this.deviceOwnershipRepository.remove(
                userId,
                existDeviceOwnership.id,
                requestLog,
                userId
            ),
            this.sessionUtil.deleteAllLogins(userId, sessions),
        ]);

        return;
    } catch (err: unknown) {
        throw new InternalServerErrorException({
            statusCode: EnumAppStatusCodeError.unknown,
            message: 'http.serverError.internalServerError',
            _error: err,
        });
    }
}

async updateMetadataByAdmin(
    id: string,
    data: FeatureFlagUpdateMetadataRequestDto
): Promise<IResponseReturn<FeatureFlagResponseDto>> {
    const featureFlag = await this.featureFlagRepository.findOneById(id);
    if (!featureFlag) {
        throw new NotFoundException({
            statusCode: EnumFeatureFlagStatusCodeError.notFound,
            message: 'featureFlag.error.notFound',
        });
    }

    const validated = this.featureFlagUtil.checkMetadataKey(
        featureFlag.metadata as IFeatureFlagMetadata,
        data.metadata
    );
    if (!validated) {
        throw new BadRequestException({
            statusCode: EnumFeatureFlagStatusCodeError.invalidMetadata,
            message: 'featureFlag.error.invalidMetadata',
        });
    }

    const [updated] = await Promise.all([
        this.featureFlagRepository.updateMetadata(id, data),
        this.featureFlagUtil.deleteCacheByKey(featureFlag.key),
    ]);

    const mapped: FeatureFlagResponseDto =
        this.featureFlagUtil.mapOne(updated);

    return {
        data: mapped,
    };
}

async processWelcomeByAdmin({
    data: { proceedBy, userId, data },
}: Job<
    INotificationWorkerPayload<INotificationWelcomeByAdminPayload>,
    unknown,
    EnumNotificationProcess
>): Promise<IQueueResponse> {
    const user = await this.userRepository.findOneActiveById(userId);

    if (!user) {
        return {
            message:
                'User not found, skipping welcome by admin notification',
        };
    }

    const notificationId = this.databaseUtil.createId();
    const emailPayload: INotificationEmailSendPayload = {
        userId: user.id,
        email: user.email,
        username: user.username,
        notificationId,
    };

    const results = await Promise.allSettled([
        this.notificationRepository.createWelcomeByAdmin(
            notificationId,
            user.id,
            user.username,
            proceedBy
        ),
        this.notificationEmailUtil.sendWelcomeByAdmin(emailPayload, data),
    ]);

    return { message: 'Welcome by admin notification processed', results };
}

