async verifyEmail(
    { token }: UserVerifyEmailRequestDto,
    requestLog: IRequestLog
): Promise<IResponseReturn<void>> {
    const hashedToken = this.userUtil.hashedToken(token);
    const verification =
        await this.userRepository.findOneActiveByVerificationEmailToken(
            hashedToken
        );
    if (!verification) {
        throw new BadRequestException({
            statusCode: EnumUserStatusCodeError.tokenInvalid,
            message: 'user.error.verificationTokenInvalid',
        });
    }

    try {
        await this.userRepository.verifyEmail(
            verification.id,
            verification.userId,
            requestLog
        );

        // @note: send email after all creation
        await this.notificationUtil.sendVerifiedEmail(verification.userId, {
            reference: verification.reference,
        });

        return;
    } catch (err: unknown) {
        throw new InternalServerErrorException({
            statusCode: EnumAppStatusCodeError.unknown,
            message: 'http.serverError.internalServerError',
            _error: err,
        });
    }
}

(processor: BullQueueProcessor) => {
  if (isAdvancedProcessor(processor)) {
    const { callback, ...processorOptions } = processor;
    return new workerClass(queueName, callback, {
      connection: options.connection,
      sharedConnection: options.sharedConnection,
      prefix: options.prefix,
      ...processorOptions,
    });
  } else if (isAdvancedSeparateProcessor(processor)) {
    const { path, ...processorOptions } = processor;
    return new workerClass(queueName, path, {
      connection: options.connection,
      sharedConnection: options.sharedConnection,
      prefix: options.prefix,
      ...processorOptions,
    });
  } else if (isSeparateProcessor(processor)) {
    return new workerClass(queueName, processor, {
      connection: options.connection,
      sharedConnection: options.sharedConnection,
      prefix: options.prefix,
    });
  } else if (isProcessorCallback(processor)) {
    return new workerClass(queueName, processor, {
      connection: options.connection,
      sharedConnection: options.sharedConnection,
      prefix: options.prefix,
    });
  }
}
